import React from 'react';
import {
  CheckCircleIcon,
  ClockIcon,
  ExclamationCircleIcon,
  UserGroupIcon,
  DocumentCheckIcon,
  FlagIcon
} from '@heroicons/react/24/outline';

const DashboardStats = ({ stats, loading }) => {
  const statCards = [
    { title: 'Total Tasks', value: stats?.total || 0, icon: DocumentCheckIcon, color: 'bg-blue-500' },
    { title: 'Completed', value: stats?.completed || 0, icon: CheckCircleIcon, color: 'bg-green-500' },
    { title: 'In Progress', value: stats?.inProgress || 0, icon: ClockIcon, color: 'bg-yellow-500' },
    { title: 'High Priority', value: stats?.highPriority || 0, icon: FlagIcon, color: 'bg-red-500' },
    { title: 'Overdue', value: stats?.overdue || 0, icon: ExclamationCircleIcon, color: 'bg-red-600' },
    { title: 'Total Staff', value: stats?.totalStaff || 0, icon: UserGroupIcon, color: 'bg-purple-500' },
  ];

  if (loading) {
    return (
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-6 gap-4">
        {[...Array(6)].map((_, i) => (
          <div key={i} className="bg-white rounded-lg shadow p-6 animate-pulse">
            <div className="h-4 bg-gray-200 rounded w-24 mb-4"></div>
            <div className="h-8 bg-gray-200 rounded w-16"></div>
          </div>
        ))}
      </div>
    );
  }

  return (
    <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-6 gap-4">
      {statCards.map((stat, index) => (
        <div key={index} className="bg-white rounded-lg shadow-sm hover:shadow-md transition-shadow p-6">
          <div className="flex items-center justify-between">
            <div>
              <p className="text-sm font-medium text-gray-600">{stat.title}</p>
              <p className="text-2xl font-bold text-gray-900 mt-1">{stat.value}</p>
            </div>
            <div className={`${stat.color} p-3 rounded-lg`}>
              <stat.icon className="w-6 h-6 text-white" />
            </div>
          </div>
        </div>
      ))}
    </div>
  );
};

export default DashboardStats;
